property.value:
//(ForStatement | ForeachStatement | WhileStatement | DoStatement)
    [
        let $loop := .
        return count(
            .//(BreakStatement | ContinueStatement)
                [
                    ancestor::*[
                        self::ForStatement
                        or self::ForeachStatement
                        or self::WhileStatement
                        or self::DoStatement
                        or self::SwitchStatement
                    ][1] is $loop
                ]
        ) > 1
    ]
